import React, { memo, useMemo } from 'react';
import GameBoard from './GameBoard';
import GameTimer from './GameTimer';

const BattleField = memo(({
    isMyTurn,
    opponentName,
    handleForfeit,
    dispPlayer,
    dispOpponent,
    handleShoot,
    explosionCells,
    noop,
    playerTimeLeft,
    turnStartedAt,
    myId,
    currentTurn,
    spectatorCount,
    isSpectator,
    lastShot,
    handleLeave,
}) => {
    // Memoize filtered props to avoid breaking child React.memo
    const playerExplosions = useMemo(() => explosionCells.filter(e => e.board === 'player'), [explosionCells]);
    const opponentExplosions = useMemo(() => explosionCells.filter(e => e.board === 'opponent'), [explosionCells]);
    const playerLastShot = useMemo(() => lastShot?.board === 'player' ? lastShot : null, [lastShot]);
    const opponentLastShot = useMemo(() => lastShot?.board === 'opponent' ? lastShot : null, [lastShot]);

    return (
        <div className="space-y-3 sm:space-y-4 animate-fade-in">
            {playerTimeLeft && Object.keys(playerTimeLeft).length > 0 && (
                <GameTimer
                    playerTimeLeft={playerTimeLeft}
                    turnStartedAt={turnStartedAt}
                    currentTurn={currentTurn}
                    myId={myId}
                    opponentName={opponentName}
                />
            )}

            <div className={`rounded-2xl p-3 sm:p-4 border text-center transition-all relative overflow-hidden ${isSpectator ? 'bg-purple-500/10 border-purple-500/40' : isMyTurn ? 'bg-gradient-to-r from-green-500/15 to-emerald-500/10 border-green-500/40 shadow-green-900/20 shadow-md' : 'bg-slate-800/60 border-slate-700'}`}>
                {isMyTurn && !isSpectator && <div className="absolute inset-0 bg-gradient-to-r from-green-500/5 via-transparent to-green-500/5 animate-pulse" />}
                <p className="text-base sm:text-lg font-black relative">
                    {isSpectator
                        ? '👁️ Spectating'
                        : isMyTurn ? '🎯 Your turn — click to fire!' : `⏳ ${opponentName} is aiming…`}
                </p>
                {!isSpectator && isMyTurn && <p className="text-xs text-green-300/70 mt-0.5 relative">Hits & sinks grant an extra shot</p>}
                <div className="absolute right-3 top-1/2 -translate-y-1/2 flex items-center gap-2">
                    {spectatorCount > 0 && (
                        <span className="px-2 py-1 bg-purple-900/40 text-purple-300 text-xs font-semibold rounded-lg border border-purple-700/40">
                            👁️ {spectatorCount}
                        </span>
                    )}
                    {isSpectator ? (
                        <button
                            onClick={handleLeave}
                            className="px-3 py-1.5 bg-red-900/40 hover:bg-red-800/60 text-red-300 text-xs font-semibold rounded-lg transition border border-red-700/40"
                            title="Leave spectator view"
                        >
                            🚪 Leave
                        </button>
                    ) : (
                        <button
                            onClick={handleForfeit}
                            className="px-3 py-1.5 bg-red-900/40 hover:bg-red-800/60 text-red-300 text-xs font-semibold rounded-lg transition border border-red-700/40"
                            title="Surrender the game"
                        >
                            🏳️ Surrender
                        </button>
                    )}
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-4 lg:gap-6">
                <div className={`bg-gradient-to-br from-slate-800/80 to-slate-900/60 rounded-2xl p-3 sm:p-4 border transition-all animate-board-entry ${isSpectator ? 'border-slate-700' : isMyTurn ? 'border-slate-700' : 'border-yellow-500/30 shadow-sm shadow-yellow-900/10'}`}>
                    <GameBoard board={dispPlayer} isYourBoard={!isSpectator} onCellClick={noop} isYourTurn={false} label={isSpectator ? `🛡️ ${opponentName || 'Player 1'}` : '🛡️ Your Fleet'} explosionCells={playerExplosions} lastShot={playerLastShot} />
                </div>
                <div className={`bg-gradient-to-br from-slate-800/80 to-slate-900/60 rounded-2xl p-3 sm:p-4 border transition-all animate-board-entry ${isSpectator ? 'border-slate-700' : isMyTurn ? 'border-green-500/30 shadow-md shadow-green-900/20 ring-1 ring-green-500/10' : 'border-slate-700'}`}>
                    <GameBoard board={dispOpponent} isYourBoard={false} onCellClick={isSpectator ? noop : handleShoot} isYourTurn={!isSpectator && isMyTurn} label={`🎯 ${opponentName || 'Player 2'}'s Waters`} explosionCells={opponentExplosions} lastShot={opponentLastShot} />
                </div>
            </div>
        </div>
    );
});

BattleField.displayName = 'BattleField';

export default BattleField;
